cj63u0g.css:
container-type: inline-size;
  counter-reset: process-list;
  gap: 0;
  display: flex;
  flex-direction: column;
  position: relative;
  > * {
    position: relative;
    counter-increment: process-list;
  }
  @media (width >= to-rem(1100px)) {
    display: grid;
    grid-template-columns: repeat(3, minmax(-0, 1fr));
    /* # Desktop Grid Lines */
    > *:not(:is(:first-child, :nth-child(4), :nth-child(7)))::before {
      content: '';
      block-size: 100%;
      inline-size: 1px;
      position: absolute;
      background: var(--border-color-dark, #ddd);
      display: flex;
      left: 0;
      top: 0;
    }
    > *:nth-child(n + 4)::after {
      content: '';
      inline-size: 100%;
      block-size: 1px;
      position: absolute;
      background: var(--border-color-dark, #ddd);
      display: flex;
      left: 0;
      top: 0;
    }
  }
  @media (width < to-rem(1100px)) {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: var(--content-gap);
    /* # Remove Grid Lines */
    &::before,
    &::after {
      display: none;
    }
    /* # Add Card Border */
    &-card {
      border: 1px solid var(--border-color-dark);
      border-radius: var(--radius, 0.5rem);
    }
  }
  @media (width < to-rem(800px)) {
    display: grid;
    grid-template-columns: repeat(1, minmax(0, 1fr));
  }

yqli4vm.css:
display: flex;
